window.MM = window.MM || {};
window.MM['anaes_p2_patho_trauma'] = [
  {q:"A trauma patient has hypotension, tachycardia and decreased breath sounds on the right before intubation. The most important diagnosis to exclude first is:",o:["Cardiac tamponade","Massive haemothorax","Tension pneumothorax","Pulmonary contusion"],a:2,e:"Positive-pressure ventilation will rapidly worsen a tension pneumothorax, causing cardiovascular collapse and cardiac arrest — it must be excluded and treated before any airway intervention.<br><br><strong>Take Notes:</strong><br>• Tension PTX: Exclude before IPPV<br>• Clinical signs: Absent breath sounds | ↑JVP | Tracheal deviation | Hypotension<br>✅ Treat clinically — do NOT wait for X-ray<br>• Needle decompression → Chest drain"},
  {q:"During trauma resuscitation, the first priority according to ATLS is:",o:["Control external bleeding","Airway management with cervical spine protection","Establish large-bore IV access","Perform FAST examination"],a:1,e:"ATLS always begins with A — airway with simultaneous cervical spine protection. Without an airway, all other interventions are futile.<br><br><strong>Take Notes:</strong><br>• ATLS primary survey: ABCDE<br>• A = Airway + C-spine | B = Breathing | C = Circulation | D = Disability | E = Exposure<br>✅ RSI frequently required for definitive airway<br>• 100% O₂ throughout"},
  {q:"Which induction agent is preferred in a severely hypovolaemic trauma patient requiring emergency surgery?",o:["Propofol","Thiopentone","Etomidate","Midazolam"],a:2,e:"Etomidate preserves SVR and cardiac output better than any other induction agent — making it the most haemodynamically safe choice in shocked trauma patients.<br><br><strong>Take Notes:</strong><br>• Etomidate: Best haemodynamic stability in trauma<br>• SVR maintained | CO maintained | BP most stable<br>⚠️ Single-dose adrenal suppression (4–8h)<br>✅ Alternative if catecholamines intact: Ketamine (bronchodilator + sympathomimetic)"},
  {q:"Which injury is the most common preventable cause of death in major trauma?",o:["Cervical spine injury","Airway obstruction","Pulmonary embolism","Acute renal failure"],a:1,e:"Failure to secure a compromised airway is consistently identified as the leading preventable cause of trauma mortality — early definitive airway management is lifesaving.<br><br><strong>Take Notes:</strong><br>• Airway obstruction: Most preventable trauma death<br>• Causes: Blood | Secretions | Tongue | Foreign body | Oedema<br>✅ Early secure airway | GCS ≤8 = Definitive airway<br>⚠️ Suction immediately available at all times"},
  {q:"A trauma patient has hypotension, distended neck veins, muffled heart sounds and tachycardia. The diagnosis is:",o:["Massive haemothorax","Cardiac tamponade","Neurogenic shock","Pulmonary contusion"],a:1,e:"Beck\'s triad (hypotension, distended neck veins, muffled heart sounds) identifies pericardial tamponade — blood in the pericardium prevents ventricular filling, causing obstructive shock.<br><br><strong>Take Notes:</strong><br>• Beck\'s triad: Cardiac tamponade<br>• Hypotension | ↑JVP | Muffled heart sounds<br>• Mechanism: Obstructive shock (impaired filling)<br>✅ Echo confirms | Treatment: Pericardiocentesis or thoracotomy"},
  {q:"Which airway manoeuvre should be avoided in a patient with suspected cervical spine injury?",o:["Jaw thrust","Manual in-line stabilisation","Head tilt-chin lift","Rapid sequence induction"],a:2,e:"Head tilt-chin lift extends the cervical spine and risks worsening an unstable injury — jaw thrust with manual in-line stabilisation (MILS) is the safe alternative.<br><br><strong>Take Notes:</strong><br>• C-spine trauma: Avoid head tilt-chin lift<br>• Use: Jaw thrust + MILS<br>• MILS: Maintains alignment during laryngoscopy<br>✅ Still perform RSI if needed — do not sacrifice airway for uncertain spinal concern"},
  {q:"Which blood product should be administered first in massive traumatic haemorrhage when immediately available?",o:["Platelets only","Fresh frozen plasma only","Packed red blood cells","Cryoprecipitate"],a:2,e:"Packed RBCs restore oxygen-carrying capacity and intravascular volume — the immediate priority in haemorrhagic shock before balanced transfusion ratios can be established.<br><br><strong>Take Notes:</strong><br>• Massive haemorrhage: PRBCs first<br>• Restores O₂-carrying capacity + Intravascular volume<br>• Immediately activate MTP (Massive Transfusion Protocol)<br>✅ Aim for 1:1:1 ratio (PRBC:FFP:Platelets) as soon as possible"},
  {q:"Which trauma patient requires immediate endotracheal intubation?",o:["GCS 14 with facial abrasion","GCS 8 after head injury","Isolated tibial fracture","Rib fracture with SpO₂ 98%"],a:1,e:"GCS ≤8 is the standard threshold for definitive airway control — patients cannot protect their airway reliably, and any deterioration may result in complete loss of airway.<br><br><strong>Take Notes:</strong><br>• GCS ≤8: Definitive airway mandatory<br>• Cannot protect airway | Aspiration risk<br>• Also intubate: Predicted deterioration | Facial burns | Expanding haematoma<br>✅ Threshold: GCS ≤8 is absolute indication"},
  {q:"Which electrolyte abnormality most commonly develops during massive blood transfusion?",o:["Hypercalcaemia","Hypermagnesaemia","Hypocalcaemia","Hyperphosphataemia"],a:2,e:"Citrate anticoagulant in stored blood chelates ionised calcium — during massive transfusion, hepatic citrate metabolism is overwhelmed, causing iCa²⁺ to fall significantly.<br><br><strong>Take Notes:</strong><br>• Massive transfusion: Citrate → iCa²⁺ ↓<br>• Impairs: Myocardial contractility + Coagulation<br>• ECG: Prolonged QT → Arrhythmias<br>✅ Replace: CaCl₂ 10 mL IV per unit of FFP in massive transfusion"},
  {q:"Which investigation is most useful for detecting free intraperitoneal fluid in an unstable trauma patient?",o:["CT abdomen","MRI abdomen","FAST examination","Diagnostic colonoscopy"],a:2,e:"FAST (Focused Assessment with Sonography for Trauma) detects haemoperitoneum and pericardial fluid at the bedside within seconds, without moving the patient to CT.<br><br><strong>Take Notes:</strong><br>• FAST: Unstable trauma standard<br>• Detects: Haemoperitoneum | Haemopericardium | Haemothorax<br>• Bedside | Rapid | No radiation | Repeatable<br>✅ eFAST adds: Bilateral pneumothorax assessment"},
  {q:"During rapid sequence induction for trauma, cricoid pressure is primarily intended to:",o:["Improve laryngoscopic view","Prevent pulmonary aspiration","Reduce cervical movement","Increase venous return"],a:1,e:"Trauma patients are universally assumed to have full stomachs — cricoid pressure occludes the oesophageal lumen against the cricoid cartilage to reduce passive regurgitation risk during apnoea.<br><br><strong>Take Notes:</strong><br>• Cricoid pressure: Aspiration prevention during RSI<br>• Applied: At induction | Released: After ETT cuff inflated and confirmed<br>⚠️ Effectiveness debated | Correct force: 30N | Do not apply if active vomiting<br>✅ Part of standard trauma RSI"},
  {q:"Which trauma-related chest injury most commonly causes severe hypoxaemia despite adequate oxygen therapy?",o:["Simple pneumothorax","Pulmonary contusion","Rib fracture","Clavicle fracture"],a:1,e:"Pulmonary contusion causes alveolar haemorrhage and oedema — perfusion continues to consolidated, non-ventilated lung units creating true shunt (V/Q = 0) that does not respond to supplemental oxygen alone.<br><br><strong>Take Notes:</strong><br>• Pulmonary contusion: Shunt physiology<br>• Alveolar haemorrhage + Oedema → V/Q = 0<br>• Peak deterioration: 48–72h post-injury<br>✅ Lung-protective ventilation (TV 6 mL/kg) + PEEP | Avoid fluid overload"},
  {q:"Which finding suggests ongoing occult haemorrhage during trauma anaesthesia?",o:["Rising ETCO₂ with hypertension","Falling ETCO₂ with persistent tachycardia","Bradycardia with hypertension","Increasing urine output"],a:1,e:"Reduced cardiac output from haemorrhage decreases pulmonary CO₂ delivery — a falling ETCO₂ accompanied by persistent tachycardia is a sensitive early warning of ongoing haemorrhagic shock.<br><br><strong>Take Notes:</strong><br>• Occult haemorrhage: Falling ETCO₂ + Tachycardia<br>• ETCO₂ ↓: CO ↓ → Less CO₂ reaching alveoli<br>• Tachycardia: Sympathetic compensation<br>✅ Act immediately: Reassess for bleeding source | Aggressive transfusion"},
  {q:"Which spinal cord injury most commonly produces neurogenic shock?",o:["Lumbar injury","Sacral injury","Cervical spinal cord injury","Coccygeal injury"],a:2,e:"High cervical or upper thoracic cord injuries sever sympathetic outflow from T1–L2, causing vasodilation and loss of cardiac sympathetic tone — producing hypotension with paradoxical bradycardia.<br><br><strong>Take Notes:</strong><br>• Neurogenic shock: High spinal cord injury<br>• Features: Hypotension | Bradycardia | Warm skin (vasodilated)<br>⚡ vs Haemorrhagic shock: Tachycardia | Cold skin | High SVR<br>✅ Treatment: Vasopressors (norepinephrine) + Atropine (bradycardia) + Fluid titration"},
  {q:"Which physiological endpoint best indicates adequate trauma resuscitation?",o:["Haemoglobin 10 g/dL","Urine output ≥0.5 mL/kg/hr","Heart rate <100/min only","Respiratory rate <20/min"],a:1,e:"Urine output of ≥0.5 mL/kg/hr reflects adequate renal perfusion, which requires sufficient cardiac output, MAP and intravascular volume — making it a practical bedside resuscitation endpoint.<br><br><strong>Take Notes:</strong><br>• Urine output ≥0.5 mL/kg/hr: Resuscitation endpoint<br>• Reflects: Renal perfusion + Adequate CO + Volume status<br>• Simple | Bedside | Continuous<br>⚡ Better endpoint: Lactate clearance (reflects tissue O₂ more directly)"},
  {q:"Which trauma patient has the highest priority for immediate surgery?",o:["Stable splenic laceration","Epidural haematoma with fixed dilated pupil","Isolated humeral fracture","Closed ankle fracture"],a:1,e:"A fixed dilated pupil with epidural haematoma indicates transtentorial herniation — surgical decompression within minutes is required to prevent irreversible brainstem compression and death.<br><br><strong>Take Notes:</strong><br>• Epidural haematoma + Fixed dilated pupil: Surgical emergency<br>• Herniation in progress | Minutes matter<br>• Classic lucid interval + Rapid deterioration<br>✅ \'Lemon-shaped\' haematoma on CT | Temporal bone fracture<br>⚠️ Do not delay for further investigations"},
  {q:"During trauma anaesthesia, permissive hypotension is contraindicated in:",o:["Isolated femur fracture","Penetrating limb injury","Severe traumatic brain injury","Isolated forearm fracture"],a:2,e:"TBI requires adequate MAP to maintain cerebral perfusion pressure — even brief hypotension worsens secondary brain injury and significantly increases mortality.<br><br><strong>Take Notes:</strong><br>• Permissive hypotension: Contraindicated in TBI<br>• Target MAP ≥80 mmHg in TBI (some guidelines: systolic ≥110 mmHg)<br>• CPP = MAP − ICP (normal CPP 60–70 mmHg)<br>✅ Safe in: Penetrating torso trauma without TBI (MAP 50–60 until haemostasis)"},
  {q:"Which acid-base disturbance most commonly develops during prolonged haemorrhagic shock?",o:["Metabolic alkalosis","Respiratory alkalosis","Metabolic acidosis","Respiratory acidosis"],a:2,e:"Haemorrhagic shock reduces tissue oxygen delivery — anaerobic metabolism generates lactic acid, producing a high anion gap metabolic acidosis proportional to shock severity.<br><br><strong>Take Notes:</strong><br>• Haemorrhagic shock: High-AG metabolic acidosis<br>• Lactate ↑ (anaerobic metabolism)<br>• Base deficit: Worsens with severity<br>• Treatment: Restore perfusion (not bicarbonate)<br>✅ Lactate >4 mmol/L: Severe shock"},
  {q:"Which airway device is considered the definitive airway in major trauma?",o:["Nasopharyngeal airway","Oropharyngeal airway","Cuffed endotracheal tube","Laryngeal mask airway"],a:2,e:"A cuffed ETT provides airway protection against aspiration, enables controlled ventilation, allows delivery of high FiO₂, and permits suctioning — the only device meeting all criteria for a \'definitive airway\'.<br><br><strong>Take Notes:</strong><br>• Definitive airway: Cuffed ETT only<br>• Provides: Aspiration protection | Controlled IPPV | Suctioning | High FiO₂<br>• LMA: NOT definitive (aspiration risk remains)<br>✅ Secure immediately: GCS ≤8 | Apnoea | Airway compromise"},
  {q:"During trauma anaesthesia, permissive hypotension aims to:",o:["Increase intracranial pressure","Reduce ongoing haemorrhage until surgical haemostasis is achieved","Increase urine output immediately","Rapidly normalise haemoglobin"],a:1,e:"Deliberately lower blood pressure reduces hydraulic pressure at bleeding sites before surgical control — limiting haemorrhage without waiting for full restoration of volume.<br><br><strong>Take Notes:</strong><br>• Permissive hypotension: Damage-control resuscitation concept<br>• Target: MAP 50–60 mmHg (systolic 80–90 mmHg) until haemostasis<br>• Reduces: Clot disruption + Haemorrhage rate<br>⚠️ Contraindications: TBI | Spinal cord injury | Elderly with fixed cardiac disease"},
  {q:"Which induction technique is recommended for most trauma patients requiring emergency surgery?",o:["Inhalational induction","Rapid sequence induction (RSI)","Awake inhalational induction","Sedation without muscle relaxants"],a:1,e:"All trauma patients are assumed to have full stomachs regardless of fasting time — RSI with rapid sequence of induction agent and succinylcholine (or high-dose rocuronium) minimises aspiration risk.<br><br><strong>Take Notes:</strong><br>• RSI: Standard trauma induction<br>• Assumes full stomach always<br>• Components: Pre-oxygenation | Induction agent | Succinylcholine or Rocuronium 1.2 mg/kg | MILS<br>✅ Avoid: Bag-mask ventilation if possible (risk of gastric distension)"},
  {q:"Which anaesthetic drug should be avoided in haemodynamically unstable trauma patients because of profound hypotension?",o:["Ketamine","Etomidate","Propofol","Fentanyl (in small doses)"],a:2,e:"Propofol causes profound vasodilation and myocardial depression — in a patient already compensating for haemorrhagic shock, this combination can precipitate cardiovascular collapse and cardiac arrest.<br><br><strong>Take Notes:</strong><br>• Propofol: Avoid in haemodynamic instability<br>• SVR ↓↓↓ + Mild myocardial depression → BP ↓↓<br>• Worsens haemorrhagic shock<br>✅ Alternatives: Etomidate (CVS neutral) | Ketamine (sympathomimetic)"},
  {q:"In early haemorrhagic shock, which physiological parameter is the last to fall?",o:["Cardiac output","Heart rate","Systemic blood pressure","Serum lactate"],a:2,e:"Sympathetic activation (tachycardia, peripheral vasoconstriction) maintains blood pressure despite significant volume loss — BP is a late and unreliable indicator of early shock.<br><br><strong>Take Notes:</strong><br>• Haemorrhagic shock: BP falls LAST<br>• Early: Tachycardia + ↑SVR compensate → BP maintained<br>• Late: Compensation fails → BP ↓ (Class III/IV shock)<br>⚠️ Normal BP does not exclude significant blood loss (Class I/II)<br>✅ Early markers: Tachycardia | Lactate ↑ | Base deficit"},
  {q:"Which trauma patient is at greatest risk of pulmonary aspiration during induction?",o:["Elective orthopaedic patient","Fasted trauma patient","Trauma patient with facial injuries and recent meal","Stable patient under regional anaesthesia"],a:2,e:"Facial trauma impairs airway protection reflexes, gastric emptying is delayed after injury, and emergency nature prevents adequate fasting — this combination creates extreme aspiration risk.<br><br><strong>Take Notes:</strong><br>• Aspiration risk: Facial trauma + Recent meal<br>• Delayed gastric emptying: Pain | Opioids | Shock<br>• Impaired reflexes: Head injury | Intoxication<br>✅ RSI mandatory | Suction immediately available | Pre-oxygenate fully"},
  {q:"Which blood product is administered to correct dilutional coagulopathy during massive transfusion?",o:["Packed red blood cells only","Fresh frozen plasma","Albumin","Dextran"],a:1,e:"FFP contains all coagulation factors — it is the essential product for replacing depleted clotting factors during massive haemorrhage and forms part of the 1:1:1 balanced transfusion strategy.<br><br><strong>Take Notes:</strong><br>• FFP: Replaces clotting factors in massive haemorrhage<br>• Contains: All soluble clotting factors + Fibrinogen<br>• Give in: 1:1:1 ratio (PRBC:FFP:Platelets)<br>✅ Cryoprecipitate: When fibrinogen <1.5 g/L | High fibrinogen content"},
  {q:"Which clinical feature best differentiates haemorrhagic shock from neurogenic shock?",o:["Bradycardia","Warm extremities","Tachycardia with cold clammy skin","Hypotension with flushed skin"],a:2,e:"Haemorrhagic shock activates sympathetic responses — tachycardia, peripheral vasoconstriction (cold skin) and ↑SVR distinguish it from neurogenic shock where sympathetic outflow is lost (bradycardia, warm skin).<br><br><strong>Take Notes:</strong><br>• Haemorrhagic vs Neurogenic shock:<br>• Haemorrhagic: Tachycardia | Cold skin | SVR ↑<br>• Neurogenic: Bradycardia | Warm skin | SVR ↓<br>✅ Both: Hypotension | Treatment differs significantly"},
  {q:"Persistent hypotension in a trauma patient despite adequate fluids should prompt evaluation for:",o:["Hyperglycaemia","Occult bleeding or obstructive shock","Mild anaemia only","Metabolic alkalosis"],a:1,e:"Failure to respond to resuscitation indicates either ongoing haemorrhage, or an obstructive cause — tamponade, tension pneumothorax and pulmonary embolism all prevent fluid response.<br><br><strong>Take Notes:</strong><br>• Fluid-refractory hypotension in trauma:<br>• Ongoing haemorrhage: Recheck FAST | Reassess sources<br>• Obstructive shock: Tamponade | Tension PTX | PE<br>✅ Use POCUS immediately | Treat reversible causes | Consider vasopressors"},
  {q:"Which component of the \'lethal triad\' most directly worsens coagulation enzyme activity?",o:["Hyperthermia","Hypothermia","Hypernatraemia","Hypercalcaemia"],a:1,e:"Coagulation enzymes lose activity exponentially as temperature falls — at 33°C enzyme activity is 50% of normal; below 30°C the coagulation cascade fails almost completely.<br><br><strong>Take Notes:</strong><br>• Lethal triad: Hypothermia | Acidosis | Coagulopathy<br>• Hypothermia: Platelet function ↓ + Enzyme activity ↓<br>✅ Prevention: Forced-air warming | Warm IV fluids | Warm theatre<br>⚠️ TEG/ROTEM better than standard coagulation tests at low temperatures"},
  {q:"Which monitoring parameter provides the earliest warning of worsening haemorrhagic shock during anaesthesia?",o:["Pulse oximetry","End-tidal CO₂","Body temperature","BIS monitor"],a:1,e:"Declining cardiac output from haemorrhage reduces CO₂ delivery to alveoli — ETCO₂ falls before blood pressure drops, providing an early, continuous alarm of circulatory deterioration.<br><br><strong>Take Notes:</strong><br>• ETCO₂: Earliest haemorrhagic shock monitor<br>• CO ↓ → CO₂ delivery to lungs ↓ → ETCO₂ ↓<br>• Precedes: Hypotension | SpO₂ ↓<br>✅ Trend matters more than absolute value | Always monitor in trauma GA"},
  {q:"In a trauma patient with suspected tension pneumothorax before IPPV:",o:["Pulmonary contusion","Flail chest","Tension pneumothorax","Simple pneumothorax"],a:2,e:"IPPV will dramatically worsen tension pneumothorax — progressive air trapping under positive pressure can cause complete cardiovascular collapse and cardiac arrest within minutes.<br><br><strong>Take Notes:</strong><br>• Tension PTX + IPPV = Cardiac arrest risk<br>• IPPV forces more air into pleural space<br>• Needle decompression: 2nd ICS MCL (or 4th/5th ICS AAL)<br>✅ Follow immediately with chest drain | Do NOT ventilate before decompression"},
  {q:"Ketamine is advantageous in hypovolaemic trauma because it:",o:["Produces profound vasodilation","Causes myocardial depression","Preserves sympathetic tone and blood pressure","Always reduces intracranial pressure"],a:2,e:"Ketamine stimulates release of endogenous catecholamines — maintaining heart rate, blood pressure and cardiac output when other induction agents would cause haemodynamic collapse.<br><br><strong>Take Notes:</strong><br>• Ketamine: Sympathomimetic induction agent<br>• Catecholamine release: BP ↑ | HR ↑ | Bronchodilation<br>• Analgesic + Preserves airway reflexes<br>⚠️ Catecholamine-depleted shock (severe/prolonged): Direct myocardial depression may emerge<br>✅ Best for: Haemorrhagic shock + Bronchospasm"},
  {q:"Which trauma-related condition requires emergency thoracotomy?",o:["Small pneumothorax","Massive haemothorax with persistent bleeding (>200 mL/h or initial >1500 mL)","Isolated pulmonary contusion","Isolated rib fracture"],a:1,e:"Massive ongoing intrathoracic haemorrhage from major vessel injury cannot be controlled with chest drainage alone — emergency thoracotomy provides direct surgical haemostasis.<br><br><strong>Take Notes:</strong><br>• Thoracotomy indications:<br>• Initial drainage >1500 mL<br>• Ongoing: >200 mL/h for 2–4h | >150 mL/h for 3h<br>• Haemodynamic instability despite chest drain<br>✅ Left anterolateral thoracotomy: Emergency arrest → Internal cardiac massage"},
  {q:"Which trauma patient should receive cervical spine immobilisation?",o:["Only patients with neck pain","Every patient with suspected major trauma mechanism until cleared","Only unconscious patients","Only patients with skull fractures"],a:1,e:"Cervical spine injury cannot be clinically excluded based on symptoms alone in the context of major trauma — immobilisation is maintained until imaging and clinical criteria confirm no injury.<br><br><strong>Take Notes:</strong><br>• C-spine immobilisation: Every major trauma patient<br>• NEXUS criteria (to allow clearance): No midline tenderness | No altered consciousness | No intoxication | No focal neurology | No distracting injury<br>✅ Hard collar + Blocks + Tape or vacuum mattress"},
  {q:"During damage-control resuscitation, excessive crystalloid is avoided because it:",o:["Improves coagulation","Worsens dilutional coagulopathy, hypothermia and tissue oedema","Significantly increases oxygen delivery","Prevents acidosis"],a:1,e:"Large crystalloid volumes dilute clotting factors (exacerbating coagulopathy), carry heat away (hypothermia), and cause interstitial oedema — compounding the lethal triad rather than correcting it.<br><br><strong>Take Notes:</strong><br>• Crystalloid excess in trauma: Harmful<br>• Dilutes: Clotting factors + Platelets → Coagulopathy<br>• Cold solutions: Hypothermia<br>• Tissue oedema: ACS | Abdominal compartment syndrome<br>✅ Damage-control: Blood products first | Crystalloid limit <1.5–2 L"},
  {q:"Which trauma patient is most likely to develop fat embolism syndrome?",o:["Mandibular fracture","Long bone or pelvic fracture","Clavicle fracture","Rib fracture"],a:1,e:"Long bone fractures (especially femur and tibia) and pelvic fractures release marrow fat into the circulation — embolisation causes the classic triad of hypoxaemia, petechiae and encephalopathy.<br><br><strong>Take Notes:</strong><br>• Fat embolism syndrome: Long bone fractures<br>• Triad: Hypoxaemia (early) | Petechiae (axilla/conjunctiva) | Neurological signs<br>• Onset: 24–72h post-fracture<br>✅ Prevention: Early operative fracture fixation | Supportive care (O₂ | PEEP | Fluids)"},
  {q:"Which physiological goal is most important during anaesthesia for traumatic brain injury?",o:["Deliberate hypotension","Maintain cerebral perfusion pressure","Deliberate hyperglycaemia","Aggressive fluid restriction"],a:1,e:"CPP (MAP − ICP) must be maintained above 60 mmHg to prevent secondary ischaemic brain injury — hypotension and hypoxia are the two most destructive factors in TBI outcomes.<br><br><strong>Take Notes:</strong><br>• TBI anaesthesia goals:<br>• CPP ≥60 mmHg (MAP ≥80 mmHg)<br>• SpO₂ ≥95% | PaO₂ ≥80 mmHg<br>• Avoid: Hypotension | Hypoxia | Hyperthermia | Hyperglycaemia<br>✅ PaCO₂: Normocapnia (35–40 mmHg) | Avoid hyper/hypoventilation"},
  {q:"Which acid-base disturbance is most predictive of severe tissue hypoperfusion in trauma?",o:["Respiratory alkalosis","Metabolic acidosis with elevated lactate","Metabolic alkalosis","Respiratory acidosis"],a:1,e:"Elevated serum lactate reflects the degree of anaerobic metabolism from tissue hypoperfusion — lactate clearance rate predicts survival better than any single clinical sign.<br><br><strong>Take Notes:</strong><br>• Lactate + Metabolic acidosis: Best shock severity marker<br>• Lactate >2: Hypoperfusion | >4: Severe shock<br>• Base deficit: Correlates with transfusion requirement<br>✅ Serial lactate: Every 1–2h during resuscitation | Target clearance >10%/2h"},
  {q:"During trauma anaesthesia, the most important overarching objective is to:",o:["Normalise haemoglobin before surgery","Preserve oxygen delivery while controlling haemorrhage","Maintain deep anaesthesia throughout","Correct all laboratory values first"],a:1,e:"Trauma anaesthesia centres on maintaining tissue oxygen delivery (CO × CaO₂), controlling haemorrhage rapidly, balanced transfusion, and preventing hypothermia/acidosis/coagulopathy.<br><br><strong>Take Notes:</strong><br>• Trauma anaesthesia core objective:<br>• O₂ delivery = CO × CaO₂: Maintain both<br>• Haemorrhage control: Surgical + Damage-control resuscitation<br>• Prevent lethal triad: Warm | Balanced transfusion | Correct acidosis"},
  {q:"During damage-control resuscitation, the recommended ratio of blood products is approximately:",o:["4:2:1","3:1:1","1:1:1","2:1:3"],a:2,e:"The PROPPR trial demonstrated that a 1:1:1 ratio of packed RBCs:FFP:platelets significantly reduced 24-hour mortality in massive haemorrhage — this balanced approach prevents dilutional coagulopathy.<br><br><strong>Take Notes:</strong><br>• Balanced transfusion: 1:1:1 (PRBC:FFP:Platelets)<br>• Evidence: PROPPR trial (2015)<br>• Add: Cryoprecipitate when fibrinogen <1.5 g/L<br>✅ TXA: 1 g IV within 3h of injury (CRASH-2)"},
  {q:"A trauma patient develops paradoxical movement of a chest wall segment after blunt injury. This indicates:",o:["Simple pneumothorax","Pulmonary embolism","Flail chest","Cardiac tamponade"],a:2,e:"Flail chest occurs when three or more adjacent ribs fracture in two places, creating a free-floating segment that moves paradoxically (in during inspiration, out during expiration).<br><br><strong>Take Notes:</strong><br>• Flail chest: ≥3 ribs fractured in ≥2 places<br>• Paradoxical movement: Segment moves in during inspiration<br>• Usually associated: Pulmonary contusion (worse than flail itself)<br>✅ Management: Adequate analgesia | IPPV if hypoxaemic | Lung-protective ventilation"},
  {q:"During massive transfusion, persistent bleeding despite surgical control most commonly results from:",o:["Hypernatraemia","Dilutional coagulopathy","Hyperalbuminaemia","Respiratory alkalosis"],a:1,e:"Replacing blood loss with RBCs alone progressively dilutes clotting factors and platelets — without FFP and platelets in balanced ratio, coagulopathy develops rapidly and bleeding cannot be controlled surgically.<br><br><strong>Take Notes:</strong><br>• Dilutional coagulopathy: Mass transfusion complication<br>• Clotting factors ↓ | Platelets ↓ | Fibrinogen ↓<br>• Manifests as: Microvascular oozing from all sites<br>✅ TEG/ROTEM guides targeted replacement<br>• Also treat: Hypothermia | Acidosis (cofactors of coagulopathy)"},
  {q:"Which trauma patient most likely requires awake fibreoptic intubation?",o:["Isolated femur fracture","Suspected cervical spine injury with anticipated difficult airway","Stable forearm fracture","Minor scalp laceration"],a:1,e:"Awake fibreoptic intubation allows the patient to maintain spontaneous ventilation and cooperate with neurological assessment — essential when C-spine injury coexists with predicted difficult airway.<br><br><strong>Take Notes:</strong><br>• Awake FOI indications in trauma:<br>• C-spine injury + Difficult airway predicted<br>• Maintains: Spontaneous ventilation | Neurological monitoring<br>⚠️ Requires cooperation and topical anaesthesia<br>✅ Alternative: Video laryngoscopy with MILS + RSI if time-critical"},
  {q:"Which parameter best reflects adequacy of tissue oxygen delivery during trauma resuscitation?",o:["Pulse pressure","Serum lactate clearance","Heart rate alone","Haemoglobin concentration alone"],a:1,e:"Serial lactate measurements reflect tissue oxygen utilisation — falling lactate (>10% reduction per 2 hours) demonstrates improving perfusion and predicts survival more accurately than clinical signs.<br><br><strong>Take Notes:</strong><br>• Lactate clearance: Best tissue perfusion marker<br>• >10% reduction per 2h = Adequate resuscitation<br>• >4 mmol/L at 12h: Significant mortality risk<br>✅ Goal-directed therapy target: Lactate <2 mmol/L + Base deficit improving"},
  {q:"Which injury is classically associated with Cushing\'s response?",o:["Massive haemothorax","Raised intracranial pressure","Neurogenic shock","Splenic rupture"],a:1,e:"Cushing\'s response (hypertension + bradycardia + irregular respiration) is a brainstem reflex to raised ICP — it represents an attempt to maintain CPP against rising ICP and is a late, ominous sign.<br><br><strong>Take Notes:</strong><br>• Cushing\'s response: Late sign of raised ICP<br>• Hypertension + Bradycardia + Irregular respiration<br>• Mechanism: Brainstem ischaemia → Sympathetic surge<br>⚠️ Late sign (herniation occurring) | Requires urgent neurosurgical intervention"},
  {q:"During anaesthesia, a sudden fall in ETCO₂ with pulseless electrical activity should immediately raise suspicion of:",o:["Acute pulmonary embolism only","Cardiac tamponade only","Tension pneumothorax only","Any of the above three reversible causes"],a:3,e:"All three — PE, tamponade, and tension pneumothorax — cause obstructive shock, reduce pulmonary blood flow, and present with PEA + abrupt ETCO₂ fall. These are the \'H\'s and T\'s\' of reversible PEA.<br><br><strong>Take Notes:</strong><br>• PEA + ↓ETCO₂ in trauma: Reversible causes<br>• 4 T\'s: Tension PTX | Tamponade | Thromboembolism | Toxins<br>• 4 H\'s: Hypoxia | Hypovolaemia | Hypo/Hyperkalaemia | Hypothermia<br>✅ Treat all simultaneously during CPR"},
  {q:"Which fluid is recommended for initial management of haemorrhagic shock before blood products are available?",o:["5% Dextrose","Hypotonic saline","Balanced isotonic crystalloid (Hartmann\'s or Plasma-Lyte)","Hypertonic glucose"],a:2,e:"Balanced crystalloids (Hartmann\'s, Plasma-Lyte) temporarily expand intravascular volume and avoid the hyperchloraemic acidosis of normal saline — they are a bridge to definitive blood product therapy.<br><br><strong>Take Notes:</strong><br>• Crystalloid in haemorrhage: Bridge therapy only<br>• Limit: <1.5–2 L before blood products available<br>• Prefer: Balanced crystalloids (Hartmann\'s) over normal saline<br>⚠️ Not a substitute for blood products — does not restore O₂ carrying capacity"},
  {q:"A trauma patient with bilateral femur fractures and hypotension is most likely suffering from:",o:["Neurogenic shock","Haemorrhagic shock","Septic shock","Cardiogenic shock"],a:1,e:"Each femur fracture can accommodate 1–2 litres of blood in the thigh compartment — bilateral fractures may account for 3–4 litres of concealed haemorrhage, causing severe haemorrhagic shock.<br><br><strong>Take Notes:</strong><br>• Bilateral femur fractures: Expect 3–4 L blood loss<br>• Hidden haemorrhage: Thigh compartment not visible<br>• Also check: Pelvis | Retroperitoneum<br>✅ Traction splints reduce blood loss by reducing fracture space volume"},
  {q:"Which trauma patient should receive tranexamic acid?",o:["Minor isolated finger injury","Major trauma with significant haemorrhage within 3 hours of injury","Stable ankle fracture","Minor scalp wound"],a:1,e:"CRASH-2 trial: TXA reduces all-cause mortality in bleeding trauma patients when given within 3 hours — after 3 hours it increases mortality and is contraindicated.<br><br><strong>Take Notes:</strong><br>• TXA: CRASH-2 trial evidence<br>• Dose: 1 g IV over 10 min | Then 1 g IV over 8h<br>• Window: Within 3 hours of injury ONLY<br>⚠️ After 3h: Harmful → Increased mortality | Do NOT give late<br>✅ Also: MATTERs trial showed benefit in military haemorrhage"},
  {q:"Which finding most strongly suggests traumatic diaphragmatic rupture?",o:["Hyperresonance only","Bowel sounds audible over the chest","Bilateral wheeze","Tracheal deviation alone"],a:1,e:"Herniation of abdominal viscera (stomach, bowel, spleen) through a diaphragmatic tear into the thorax allows bowel peristalsis to be heard through a stethoscope placed on the chest.<br><br><strong>Take Notes:</strong><br>• Diaphragmatic rupture: Bowel sounds over chest<br>• More common: Left side (stomach/bowel herniates)<br>• Right: Liver fills defect (may be clinically silent)<br>• Chest X-ray: NG tube in chest | Air-fluid level in thorax<br>✅ Confirm with CT | Surgical repair required"},
  {q:"Which polytrauma patient is at greatest risk of aspiration pneumonitis?",o:["Elective fasting patient","Polytrauma patient with decreased consciousness","Stable outpatient","Local anaesthesia patient"],a:1,e:"Reduced GCS from head injury eliminates protective reflexes; pain and opioids delay gastric emptying; the full stomach assumption must always apply — this patient is at extreme aspiration risk.<br><br><strong>Take Notes:</strong><br>• Aspiration risk factors in trauma:<br>• GCS ↓ → Lost laryngeal reflexes<br>• Delayed gastric emptying: Pain | Opioids | Shock<br>• Assume full stomach in ALL trauma patients<br>✅ RSI + Suction available | PEEP for aspiration pneumonitis"},
  {q:"Which monitoring modality provides continuous ventilation assessment during trauma anaesthesia?",o:["Pulse oximetry","Capnography","Temperature monitoring","Arterial line"],a:1,e:"Capnography continuously monitors every breath — detecting airway disconnection, inadvertent extubation, bronchospasm and respiratory changes that precede haemodynamic events.<br><br><strong>Take Notes:</strong><br>• Capnography: Mandatory in all trauma GA<br>• Confirms ETT position | Detects disconnection | Monitors ventilation<br>• Bronchospasm: Shark-fin waveform<br>• Circulatory compromise: ETCO₂ ↓<br>✅ Mandated by AAGBI/ASA standards for every GA"},
  {q:"Which complication is most likely after prolonged hypotension in major trauma?",o:["Acute tubular necrosis","Hyperthyroidism","Hypercalcaemia","Polycythaemia"],a:0,e:"Sustained renal hypoperfusion (MAP <65 mmHg) causes ischaemic injury to the highly metabolically active proximal tubule — the most common cause of postoperative AKI after major trauma.<br><br><strong>Take Notes:</strong><br>• Prolonged hypotension → Acute Tubular Necrosis<br>• PCT most vulnerable: High O₂ demand + ATP-dependent<br>• Manifestation: Oliguria → Rising creatinine 24–72h post-trauma<br>✅ Prevention: Maintain MAP ≥65 mmHg throughout | Avoid nephrotoxins"},
  {q:"Which factor contributes most to the \'lethal triad\' perpetuating uncontrolled bleeding?",o:["Hyperthermia","Hypoglycaemia","Coagulopathy","Hypernatraemia"],a:2,e:"The lethal triad (hypothermia, acidosis, coagulopathy) forms a vicious cycle — coagulopathy causes more haemorrhage → more shock → more acidosis and hypothermia → worse coagulopathy.<br><br><strong>Take Notes:</strong><br>• Lethal triad: Hypothermia + Acidosis + Coagulopathy<br>• Coagulopathy: Central mechanism perpetuating haemorrhage<br>⚡ Break the cycle: Warm | Buffer acidosis | Balanced transfusion + TXA<br>✅ TEG/ROTEM: Identifies specific coagulation defects to target"},
  {q:"Failure to adequately preoxygenate before RSI in a trauma patient primarily increases the risk of:",o:["Hyperkalaemia","Rapid arterial desaturation during apnoea","Aspiration of blood only","Bronchospasm"],a:1,e:"Trauma patients often have reduced FRC (pain, anxiety, supine position), increased O₂ consumption (catecholamines, pain) and possible anaemia — leaving a narrow safe apnoea window without adequate denitrogenation.<br><br><strong>Take Notes:</strong><br>• Preoxygenation in trauma RSI:<br>• Goal: EtO₂ >90% (denitrogenation)<br>• 3–5 min tidal breathing OR 8 vital-capacity breaths<br>⚠️ Obese/Pregnant/Injured: FRC ↓ → Faster desaturation<br>✅ Upright/reverse Trendelenburg improves FRC in spontaneously breathing patients"},
  {q:"Which trauma patient is the best candidate for ketamine induction?",o:["Stable elective patient with hypertension","Haemorrhagic shock without severe myocardial failure","Cardiogenic shock after MI","Patient with uncontrolled thyrotoxicosis"],a:1,e:"Ketamine\'s sympathomimetic effect maintains BP and CO through catecholamine release — ideal in haemorrhagic shock provided endogenous catecholamine stores remain replete.<br><br><strong>Take Notes:</strong><br>• Ketamine best indication: Haemorrhagic shock<br>• Sympathomimetic + Bronchodilator + Preserves airway reflexes<br>• Dose: 1–2 mg/kg IV (reduce dose if near catecholamine depletion)<br>⚠️ Catecholamine-depleted severe shock: Direct myocardial depression may emerge → BP ↓"},
  {q:"A trauma patient has sudden hypotension after induction despite apparently adequate fluid resuscitation. The most likely cause is:",o:["Drug allergy","Unrecognised ongoing haemorrhage with sympatholysis on induction","Hypoglycaemia","Hyperventilation"],a:1,e:"Induction abolishes the compensatory sympathetic response — a patient who appeared adequately resuscitated may have been compensating for 30–40% volume deficit (Class III haemorrhage) that induction unmasks.<br><br><strong>Take Notes:</strong><br>• Post-induction hypotension: Sympatholysis unmasks shock<br>• Compensated shock (Class II/III): HR ↑ + SVR ↑ masks BP deficit<br>• Induction: Sympathetic tone ↓ → BP collapses<br>✅ Always: Reassess FAST | Activate MTP | Check pericardium | Vasopressors"},
  {q:"Which investigation most accurately identifies trauma-induced coagulopathy in real time?",o:["ESR","ROTEM or TEG","Serum bilirubin","HbA1c"],a:1,e:"Viscoelastic testing (ROTEM/TEG) characterises the entire clot formation, strength and fibrinolysis cycle within 10–30 minutes — enabling goal-directed, targeted blood product replacement.<br><br><strong>Take Notes:</strong><br>• ROTEM/TEG: Real-time coagulopathy assessment<br>• Identifies: Clot formation time | Clot strength | Fibrinolysis<br>• Guides: Specific product replacement (FFP vs Cryo vs Platelets vs TXA)<br>✅ Superior to: PT/APTT/INR for trauma coagulopathy guidance"},
  {q:"Which injury should always be suspected in a patient with left lower rib fractures and hypotension?",o:["Pulmonary embolism","Splenic injury","Thyroid injury","Oesophageal rupture"],a:1,e:"The spleen lies adjacent to ribs 9–11 on the left — fractures here should always raise suspicion of splenic laceration and occult intra-abdominal haemorrhage even without external evidence of bleeding.<br><br><strong>Take Notes:</strong><br>• Left rib 9–11 fractures + Hypotension: Suspect spleen<br>• Spleen: Most commonly injured solid organ in blunt trauma<br>• FAST: Left upper quadrant for free fluid<br>✅ Unstable: Emergency laparotomy | Stable: CT then angioembolism or conservative"},
  {q:"Which ventilation strategy is preferred in pulmonary contusion?",o:["High tidal volume without PEEP","Lung-protective ventilation with appropriate PEEP","Routine hyperventilation","Zero end-expiratory pressure"],a:1,e:"Pulmonary contusion responds to PEEP (recruits collapsed, oedematous alveoli) and low tidal volume (prevents ventilator-induced lung injury) — the same approach as ARDS management.<br><br><strong>Take Notes:</strong><br>• Pulmonary contusion: Lung-protective ventilation<br>• TV: 6 mL/kg IBW | PEEP: 5–10 cmH₂O<br>• Plateau pressure: <30 cmH₂O<br>• Permissive hypercapnia: Acceptable (PaCO₂ 45–60 mmHg)<br>✅ Avoid fluid overload: Worsens alveolar oedema"},
  {q:"Which trauma patient requires immediate massive transfusion protocol activation?",o:["Stable isolated wrist fracture","Persistent hypotension with suspected major haemorrhage","Minor scalp laceration","Isolated ankle fracture"],a:1,e:"Early MTP activation delivers balanced blood products before haemodynamic deterioration becomes irreversible — delay in product delivery is independently associated with mortality.<br><br><strong>Take Notes:</strong><br>• MTP activation criteria:<br>• Persistent hypotension (SBP <90) + Suspected major haemorrhage<br>• TASH score | ABC score | Clinical judgement<br>• Delivers: PRBCs + FFP + Platelets in 1:1:1 ratio pre-mixed<br>✅ Contact blood bank immediately | Do not delay"},
  {q:"Which physiological response initially compensates for acute haemorrhage?",o:["Bradycardia","Peripheral vasoconstriction with tachycardia","Reduced SVR","Increased urine output"],a:1,e:"The baroreceptor reflex triggers immediate sympathetic activation — increasing HR (maintaining CO) and peripheral vasoconstriction (maintaining MAP and diverting blood to vital organs).<br><br><strong>Take Notes:</strong><br>• Compensation for acute haemorrhage:<br>• Baroreceptors → Sympathetic ↑ → HR ↑ + SVR ↑<br>• Catecholamines: Epinephrine + NE from adrenal medulla<br>• RAAS + ADH: Volume retention (slower)<br>✅ Class I (<15%): No symptoms | Class II (15–30%): Tachycardia"},
  {q:"During trauma anaesthesia, persistent metabolic acidosis despite adequate ventilation most likely indicates:",o:["Hyperventilation syndrome","Ongoing tissue hypoperfusion from haemorrhage","Excess bicarbonate therapy","Respiratory alkalosis"],a:1,e:"Ongoing acidosis with correct ventilation (normal PaCO₂) means lactate continues to be generated — unresolved haemorrhage or inadequate resuscitation is the most likely cause.<br><br><strong>Take Notes:</strong><br>• Persistent metabolic acidosis during trauma GA:<br>• CO₂ eliminated = Normal PaCO₂ → Not respiratory<br>• Lactate still rising: Ongoing haemorrhage or inadequate resuscitation<br>✅ Act: Identify bleeding source | Increase transfusion | Vasopressors"},
  {q:"Which mechanism contributes most to trauma-induced coagulopathy?",o:["Increased platelet production","Tissue hypoperfusion activating anticoagulant pathways","Hypercalcaemia","Increased fibrinogen synthesis"],a:1,e:"Shock activates the protein C pathway and causes shedding of endothelial thrombomodulin — consuming factors V and VIII and activating fibrinolysis before any dilution occurs (acute traumatic coagulopathy).<br><br><strong>Take Notes:</strong><br>• Acute traumatic coagulopathy: Shock-induced<br>• Mechanism: Protein C activation → Factors V/VIII consumed + Fibrinolysis ↑<br>• Occurs early (before massive transfusion)<br>⚠️ Different from dilutional coagulopathy | Both need treating<br>✅ TXA effective against fibrinolysis component"},
  {q:"Which anaesthetic complication is most likely if occult hypovolaemia is not recognised before induction?",o:["Severe hypertension","Profound cardiovascular collapse","Bronchospasm only","Delayed emergence only"],a:1,e:"Induction abolishes compensatory sympathetic tone — a patient in compensated haemorrhagic shock loses all reserves simultaneously, causing precipitous cardiac output reduction and potentially cardiac arrest.<br><br><strong>Take Notes:</strong><br>• Occult hypovolaemia + Induction = Cardiovascular collapse<br>• Pre-induction: Resuscitate as much as time allows<br>• Use: Reduced-dose etomidate or ketamine<br>• Have: Vasopressors drawn up before induction<br>✅ Standard: Phenylephrine 100 μg IV or Norepinephrine infusion ready"},
  {q:"Which trauma patient is at greatest risk of developing ARDS?",o:["Minor forearm fracture","Severe pulmonary contusion with massive transfusion requirement","Isolated ankle sprain","Nasal fracture"],a:1,e:"Severe pulmonary contusion directly injures alveolar-capillary membranes; massive transfusion drives systemic inflammation (TRALI risk) — together these create ideal conditions for ARDS development.<br><br><strong>Take Notes:</strong><br>• ARDS risk in trauma:<br>• Pulmonary contusion + Massive transfusion + Sepsis<br>• TRALI: Transfusion-Related Acute Lung Injury<br>• Berlin definition: PaO₂/FiO₂ <300 + Bilateral infiltrates + Non-cardiac<br>✅ Use: Lung-protective ventilation | PEEP | Prone positioning if severe"},
  {q:"During damage-control surgery, the primary anaesthetic goal is:",o:["Complete physiological normalisation before leaving theatre","Short operation with rapid haemorrhage control and decontamination","Deep anaesthesia for several hours","Aggressive crystalloid administration"],a:1,e:"Damage-control surgery: stop the bleeding and contamination quickly, then transfer to ICU for physiological restoration — prolonging surgery in a coagulopathic, hypothermic, acidotic patient dramatically increases mortality.<br><br><strong>Take Notes:</strong><br>• Damage-control surgery: Brief, targeted<br>• Phase 1: Stop haemorrhage + Contamination | Temporary closure<br>• Phase 2: ICU resuscitation (correct triad)<br>• Phase 3: Definitive repair when physiology restored<br>✅ Anaesthesia: Minimal agents | Body warming | Maintain perfusion"},
  {q:"Emergency thoracotomy in trauma is classically indicated when initial chest drain output exceeds:",o:["500 mL immediately","1500 mL immediately or >200 mL/h ongoing","300 mL immediately","700 mL over 2 hours"],a:1,e:"Initial chest tube drainage >1500 mL or ongoing haemorrhage >200 mL/h indicates major intrathoracic vessel injury that requires direct surgical control.<br><br><strong>Take Notes:</strong><br>• Thoracotomy indications:<br>• Initial: >1500 mL drainage<br>• Ongoing: >200 mL/h for 2h | >150 mL/h for 3h<br>• Clinical: Persistent haemodynamic instability from chest<br>✅ Resuscitative thoracotomy (ED): Penetrating cardiac arrest"},
  {q:"Which physiological abnormality most impairs coagulation enzyme activity during trauma?",o:["Hyperthermia","Hypothermia","Hyperglycaemia","Hyperoxia"],a:1,e:"Coagulation enzyme kinetics follow a Q10 rule — for every 1°C fall, enzyme activity decreases approximately 10%; at 33°C activity is approximately 50% of normal.<br><br><strong>Take Notes:</strong><br>• Hypothermia: Coagulation enzymes fail<br>• 33°C: ≈50% enzyme activity<br>• <30°C: Near-complete coagulation failure<br>• Platelet function: Also impaired by hypothermia<br>✅ Active warming: Forced-air | Warm IV fluids | Warm theatre | Humidified gases"},
  {q:"Which bedside investigation guides targeted transfusion in real-time trauma coagulopathy?",o:["ESR","ROTEM/TEG","Serum bilirubin","HbA1c"],a:1,e:"Viscoelastic haemostatic assays produce a dynamic graphical representation of clot formation, strength and lysis within 10–30 minutes — enabling targeted rather than empirical blood product replacement.<br><br><strong>Take Notes:</strong><br>• ROTEM/TEG: Goal-directed trauma transfusion<br>• Identifies: Which specific factor/platelet/fibrinogen is deficient<br>• Guides: Specific products → Less waste | Better outcomes<br>✅ ITACTIC trial: TEG/ROTEM guides as good as empirical 1:1:1"},
  {q:"Which injury should always be suspected in a hypotensive trauma patient with pelvic fracture?",o:["Massive retroperitoneal haemorrhage","Myocardial infarction","Acute pancreatitis","Pericarditis"],a:0,e:"The pelvis contains a rich venous plexus (Batson\'s plexus) and major iliac vessels — pelvic fractures can cause 4–6 litres of concealed retroperitoneal haemorrhage.<br><br><strong>Take Notes:</strong><br>• Pelvic fracture: Retroperitoneal haemorrhage<br>• Blood loss: 4–6 L possible<br>• Initial: Pelvic binder (closes volume → reduces bleeding)<br>✅ Haemodynamically unstable: Angioembolism | Preperitoneal packing | PPH<br>⚠️ FAST may miss retroperitoneal blood (not intraperitoneal)"},
  {q:"Persistent hypotension despite haemorrhage control and blood transfusion in trauma should prompt evaluation for:",o:["Occult obstructive shock","Hyperglycaemia","Hypothyroidism","Hypernatraemia"],a:0,e:"If haemorrhage is controlled and volume is replaced, persistent hypotension must have another cause — tamponade, tension pneumothorax, or PE must be urgently sought with POCUS.<br><br><strong>Take Notes:</strong><br>• Persistent hypotension despite haemorrhage control:<br>• First: Reassess haemorrhage (missed source?)<br>• Then: Obstructive shock (tamponade | Tension PTX | PE)<br>✅ POCUS immediately: Cardiac | Pleural | Abdominal<br>⚠️ Consider: Spinal shock | Adrenal crisis | Myocardial contusion"},
  {q:"Which trauma patient has the greatest indication for invasive arterial monitoring before induction?",o:["Stable wrist fracture","Haemodynamically unstable polytrauma patient","Minor scalp laceration","Elective hand surgery"],a:1,e:"Continuous beat-to-beat blood pressure monitoring allows immediate detection of haemodynamic changes and provides access for frequent arterial blood gas sampling during major trauma anaesthesia.<br><br><strong>Take Notes:</strong><br>• Arterial line: Unstable polytrauma standard<br>• Beat-to-beat BP | Frequent ABGs<br>• Radial artery most common (check Allen\'s test)<br>✅ Insert before induction or simultaneously<br>• Femoral artery: Alternative if upper limb inaccessible"},
  {q:"Failure to prevent hypothermia during trauma surgery contributes directly to:",o:["Improved coagulation","Increased oxygen delivery","Coagulopathy, increased transfusion and mortality","Reduced blood loss"],a:2,e:"Hypothermia is part of the lethal triad — it impairs coagulation enzyme and platelet function, increases transfusion requirements and independently doubles mortality in trauma.<br><br><strong>Take Notes:</strong><br>• Hypothermia in trauma: Major preventable contributor to death<br>• Impairs: Coagulation enzymes + Platelet function<br>• ↑ Transfusion requirements + ↑ Mortality<br>✅ Active warming: Forced-air | Warm IV fluids (38–40°C) | Theatre temperature ↑ | Warm anaesthetic gases"},
  {q:"Which trauma-related complication is most likely after prolonged crush injury followed by reperfusion?",o:["Hypercalcaemia","Hyperkalaemia","Hypernatraemia","Hypoglycaemia"],a:1,e:"Crush syndrome causes myocyte necrosis with massive K⁺ release; reperfusion delivers this accumulated K⁺ to the systemic circulation — life-threatening hyperkalaemia and cardiac arrhythmias may develop immediately on tourniquet release.<br><br><strong>Take Notes:</strong><br>• Crush syndrome: Hyperkalaemia on reperfusion<br>• Mechanism: Myocyte necrosis → K⁺ + Myoglobin released<br>• Also: Metabolic acidosis + Myoglobinuria → AKI<br>⚠️ ECG monitor before tourniquet release | Have: Ca gluconate + Insulin/Glucose + Bicarbonate ready<br>✅ Also expect: Hypotension on limb reperfusion"},
  {q:"Which statement best describes the trauma anaesthesiologist\'s role in major trauma?",o:["Provide anaesthesia only after surgery begins","Focus only on airway management","Coordinate resuscitation, airway, transfusion and physiology simultaneously","Avoid involvement in massive transfusion decisions"],a:2,e:"The trauma anaesthesiologist integrates airway management, haemodynamic resuscitation, massive transfusion, ventilation, temperature control and communication — functioning as the team leader for physiology in the operating theatre.<br><br><strong>Take Notes:</strong><br>• Trauma anaesthesiologist: Multitasking team leader<br>• Simultaneously: Airway | Haemodynamics | Transfusion | Temperature | Ventilation<br>• Communicates: With surgeons | Blood bank | ICU<br>✅ Damage-control resuscitation requires this integration"},
  {q:"A severely injured patient develops hypothermia, metabolic acidosis, diffuse coagulopathy, rising lactate and persistent hypotension despite aggressive resuscitation. This is:",o:["Cushing\'s triad","Beck\'s triad","The lethal triad progressing to the \'bloody vicious cycle\'","Systemic inflammatory response syndrome"],a:2,e:"Hypothermia, acidosis and coagulopathy reinforce each other in a self-amplifying cycle — coagulopathy causes haemorrhage → worse shock → more acidosis and hypothermia → worse coagulopathy → patient dies.<br><br><strong>Take Notes:</strong><br>• Bloody vicious cycle = Lethal triad self-amplifying<br>• Break with: Damage-control surgery + Balanced transfusion + TXA<br>• Warm | Buffer acidosis | Replace coagulation factors<br>✅ Recognition and early intervention are the only way to interrupt this cycle"},
  {q:"A trauma patient with penetrating chest injury becomes profoundly hypotensive after induction. JVP is raised and heart sounds muffled. The most important step is:",o:["Massive haemothorax","Pericardiocentesis or surgical decompression of cardiac tamponade","Neurogenic shock","Pulmonary contusion treatment"],a:1,e:"Induction and positive-pressure ventilation reduce venous return to an already-compromised ventricle, precipitating cardiovascular collapse in tamponade — immediate pericardial decompression is life-saving.<br><br><strong>Take Notes:</strong><br>• Cardiac tamponade + Induction: Cardiovascular collapse<br>• IPPV worsens: Further reduces venous return<br>• Emergency: Pericardiocentesis | Subxiphoid window | Thoracotomy<br>✅ Maintain high preload pre-induction | Ketamine or etomidate preferred<br>⚠️ Avoid PEEP: Worsens tamponade physiology"},
  {q:"Which arterial blood gas parameter correlates best with the severity of haemorrhagic shock?",o:["PaO₂","Base deficit","SaO₂","PaCO₂"],a:1,e:"Base deficit reflects cumulative tissue oxygen debt — the more severe the shock, the greater the base deficit. It correlates with transfusion requirements, morbidity and mortality.<br><br><strong>Take Notes:</strong><br>• Base deficit: Shock severity correlator<br>• BD >6: Significant shock | BD >10: Severe<br>• Predicts: Transfusion requirement + Complications<br>✅ Serial base deficit: Better than single measurement | Normalisation = Resuscitation success"},
  {q:"During RSI in trauma, failed first-pass intubation primarily increases the risk of:",o:["Hypernatraemia","Aspiration and hypoxaemia","Hyperglycaemia","Bradycardia only"],a:1,e:"Repeated laryngoscopy prolongs apnoea duration, risks regurgitation from manipulation, and fails to secure the airway — hypoxaemia and aspiration can occur rapidly in an already compromised trauma patient.<br><br><strong>Take Notes:</strong><br>• Failed first-pass intubation in RSI:<br>• Prolonged apnoea → Desaturation (especially in reduced FRC)<br>• Repeated manipulation → Regurgitation risk<br>✅ Must have: Backup plan (VL | Bougie | SGA | Front-of-neck) BEFORE induction<br>• DAS failed airway guideline: Declare early | Call for help"},
  {q:"Which injury most commonly produces obstructive shock after blunt chest trauma?",o:["Liver laceration","Tension pneumothorax","Splenic injury","Pelvic fracture"],a:1,e:"Air trapping in the pleural space progressively increases intrathoracic pressure, compressing the heart and great veins — venous return falls catastrophically, causing obstructive shock.<br><br><strong>Take Notes:</strong><br>• Tension PTX: Obstructive shock from blunt chest<br>• Mechanism: Air → Pleural space → Mediastinal shift → IVC/RA compression → Venous return ↓<br>✅ Clinical diagnosis: Absent breath sounds | ↑JVP | Tracheal deviation<br>⚠️ Never wait for CXR — decompress immediately"},
  {q:"Which trauma patient has the highest risk of fat embolism syndrome?",o:["Bilateral femoral shaft fractures","Isolated humeral fracture","Nasal fracture","Mandibular fracture"],a:0,e:"Multiple long-bone fractures dramatically increase marrow fat release — bilateral femoral fractures provide the largest fat-releasing surfaces and carry the highest risk of fat embolism syndrome.<br><br><strong>Take Notes:</strong><br>• Fat embolism: Bilateral femoral fractures highest risk<br>• Classic triad: Hypoxaemia | Petechiae | Neurological symptoms (confusion)<br>• Timing: 12–72h post-injury<br>• Petechiae: Axilla | Conjunctiva | Chest | Upper body<br>✅ Prevention: Early fixation | Supportive care | High FiO₂"},
  {q:"Which ventilation parameter is critical to monitor to avoid secondary injury in traumatic brain injury?",o:["Respiratory rate alone","PaCO₂ — avoid hypocapnia and hypercapnia","Tidal volume alone","Inspiratory flow rate"],a:1,e:"Both hypocapnia (cerebral vasoconstriction → ischaemia) and hypercapnia (cerebral vasodilation → ICP rise) worsen TBI — normocapnia (PaCO₂ 35–40 mmHg) must be maintained precisely.<br><br><strong>Take Notes:</strong><br>• TBI ventilation: Normocapnia essential<br>• PaCO₂ target: 35–40 mmHg<br>• Hypocapnia (<35): Cerebral ischaemia<br>• Hypercapnia (>45): CBF ↑ → ICP ↑<br>⚠️ Brief hyperventilation (25–30 mmHg): Only for acute herniation | 15–20 min maximum"},
  {q:"Which injury is most commonly missed during the primary survey?",o:["Long bone fracture","Diaphragmatic rupture","Scalp laceration","Patellar fracture"],a:1,e:"Diaphragmatic rupture may be clinically silent initially, especially on the right where the liver occludes the defect — the diagnosis is frequently delayed or missed on initial chest X-ray.<br><br><strong>Take Notes:</strong><br>• Diaphragmatic rupture: Commonly missed<br>• Left side: Bowel/stomach herniation → More obvious<br>• Right side: Liver fills defect → Clinically silent<br>• CXR: Often normal or non-specific<br>✅ CT chest/abdomen required for diagnosis | Maintain clinical suspicion"},
  {q:"Which analgesic approach is most appropriate for flail chest to prevent respiratory failure?",o:["Systemic opioids alone","Thoracic epidural or paravertebral block","Simple analgesia only","NSAIDs exclusively"],a:1,e:"Adequate analgesia enables deep breathing and effective coughing — thoracic epidural or paravertebral blocks provide superior analgesia to systemic opioids without respiratory depression.<br><br><strong>Take Notes:</strong><br>• Flail chest: Regional analgesia preferred<br>• Thoracic epidural: Gold standard (bilateral effects)<br>• Paravertebral block: Unilateral | Safer in coagulopathy<br>• Serratus anterior plane block: Emerging alternative<br>✅ Goal: Enable breathing + Coughing | Prevent respiratory failure | Avoid opioid hypoventilation"},
  {q:"Which finding in a trauma patient indicates Class IV haemorrhagic shock?",o:["Heart rate 95, BP 118/75, RR 14","Heart rate 130, BP 90/60, RR 30, confused","Heart rate 140, BP unrecordable, unconscious, anuric","Heart rate 110, BP 110/70, anxious"],a:2,e:"Class IV shock (>40% blood loss): Unrecordable BP, extreme tachycardia, unconsciousness and anuria — immediate massive transfusion and emergency surgery are required or death is imminent.<br><br><strong>Take Notes:</strong><br>• ATLS Haemorrhagic Shock Classes:<br>• Class I (<15%): HR <100 | Normal BP<br>• Class II (15–30%): HR 100–120 | Anxious<br>• Class III (30–40%): HR >120 | BP ↓ | Confused<br>• Class IV (>40%): HR >140 | BP unrecordable | Unconscious"},
  {q:"Which drug should be given before surgical scrubbing to optimise TBI outcomes?",o:["Mannitol alone regardless of BP","Dexamethasone routinely","Phenobarbitone prophylactically","Phenytoin routinely"],a:0,e:"Mannitol (0.25–1 g/kg IV) creates an osmotic gradient between brain parenchyma and intravascular space, acutely reducing brain water content and ICP — most effective when given before herniation becomes irreversible.<br><br><strong>Take Notes:</strong><br>• Mannitol in TBI:<br>• Dose: 0.25–1 g/kg IV as bolus<br>• Mechanism: Osmotic dehydration of brain + Rheological: ↓ Blood viscosity → CBF ↑<br>⚠️ Requires adequate MAP (osmotherapy worsens hypotension)<br>✅ Hypertonic saline (3–8%): Alternative | Better if haemodynamically compromised"},
  {q:"Which surgical strategy should be employed when a trauma patient develops the lethal triad during a long operation?",o:["Extend surgery to achieve definitive repair","Abandon surgery when lethal triad develops, close temporarily and transfer to ICU","Increase anaesthetic depth","Administer large volumes of crystalloid"],a:1,e:"Damage-control surgery means stopping as soon as haemorrhage and contamination are controlled, regardless of completion — physiological restoration in the ICU must precede definitive repair.<br><br><strong>Take Notes:</strong><br>• Damage-control surgery: Stop and stabilise<br>• Detect lethal triad early: Temperature | pH | Coagulation<br>• Close temporarily: Bogota bag | Negative pressure dressing<br>• ICU phase: Warm | Correct coagulopathy | Resuscitate<br>✅ Definitive surgery: Only when physiology restored"},
  {q:"Which type of shock is characterised by hypotension, bradycardia, and warm peripheries in a trauma patient?",o:["Haemorrhagic shock","Cardiogenic shock","Neurogenic shock","Septic shock (early)"],a:2,e:"Neurogenic shock from high spinal cord injury causes sympathetic denervation — loss of both vasomotor tone (vasodilation → warm skin) and cardiac sympathetic input (bradycardia) produces a distinctive distributive shock picture.<br><br><strong>Take Notes:</strong><br>• Neurogenic shock: Distinctive pattern<br>• Hypotension + Bradycardia + Warm skin + Priapism<br>⚡ Septic shock (early): Also warm + Tachycardia<br>✅ Exclude haemorrhage first (haemorrhage is common, neurogenic is a diagnosis of exclusion)<br>• Treatment: Vasopressors (NE) + Atropine + Volume"},
  {q:"A severely head-injured patient has an ICP monitor showing ICP = 38 mmHg and MAP = 78 mmHg. What is the CPP, and is it adequate?",o:["CPP = 116 mmHg — excessive","CPP = 40 mmHg — critically low","CPP = 78 mmHg — adequate","CPP = 38 mmHg — normal"],a:1,e:"CPP = MAP − ICP = 78 − 38 = 40 mmHg — critically below the recommended threshold of 60–70 mmHg. This level of ischaemia will cause secondary brain injury and requires immediate intervention.<br><br><strong>Take Notes:</strong><br>• CPP = MAP − ICP = 78 − 38 = 40 mmHg<br>• Critical: Below target (60–70 mmHg)<br>✅ Interventions: ↑ MAP (vasopressors) + ↓ ICP (mannitol | position | drainage)<br>• Target: CPP 60–70 mmHg | MAP ≥80 mmHg in TBI"}
];